def parse_iso8601_interval(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    parts = value.split('/')
    if len(parts) != 2:
        raise ValueError('ISO 8601 interval must be in format "start/end"') from None
    return {'account_notification_start_at': parts[0], 'account_notification_end_at': parts[1]}

def build_account_services(service_name: str | None = None, enabled: bool | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if service_name is None and enabled is None:
        return None
    if service_name is None or enabled is None:
        raise ValueError("Both service_name and enabled must be provided together") from None
    return {service_name: enabled}

def build_appointment_time_slots(appointment_group_new_appointments_start_times: str | None = None, appointment_group_new_appointments_end_times: str | None = None) -> list | None:
    """Helper function for parameter transformation"""
    if appointment_group_new_appointments_start_times is None or appointment_group_new_appointments_end_times is None:
        return None

    if len(appointment_group_new_appointments_start_times) != len(appointment_group_new_appointments_end_times):
        raise ValueError("Start times and end times arrays must have equal length") from None

    if len(appointment_group_new_appointments_start_times) == 0:
        raise ValueError("At least one time slot must be provided") from None

    time_slots = []
    try:
        for start_str, end_str in zip(appointment_group_new_appointments_start_times, appointment_group_new_appointments_end_times):
            start = datetime.fromisoformat(start_str.replace('Z', '+00:00'))
            end = datetime.fromisoformat(end_str.replace('Z', '+00:00'))
            if start >= end:
                raise ValueError(f"Start time {start_str} must be before end time {end_str}") from None
            time_slots.append({"start_at": start_str, "end_at": end_str})
    except (ValueError, AttributeError, TypeError) as e:
        raise ValueError(f"Failed to build appointment time slots: {e}") from e

    return time_slots

