# ============================================================================

mcp = FastMCP("Canvas")

# Tags: plagiarism_detection_platform_assignments
@mcp.tool()
async def get_assignment_lti(assignment_id: str = Field(..., description="The Canvas assignment ID or LTI assignment ID that uniquely identifies the assignment to retrieve.")) -> dict[str, Any]:
    """Retrieve a single Canvas assignment by its Canvas ID or LTI ID. Tool providers can only access assignments associated with their tool."""

    # Construct request model with validation
    try:
        _request = _models.GetSingleAssignmentLtiRequest(
            path=_models.GetSingleAssignmentLtiRequestPath(assignment_id=assignment_id)
        )
    except pydantic.ValidationError as _validation_err:
        logging.error(f"Parameter validation failed for get_assignment_lti: {_validation_err}")
        raise ValueError(f"Invalid parameters: {_validation_err.errors()}") from _validation_err

    # Generate request ID
    _request_id = str(uuid.uuid4())

    # Log invocation
    _log_tool_invocation("get_assignment_lti", "GET", "/lti/assignments/{assignment_id}", _request_id)

    # Extract parameters for API call
    _http_path = _build_path("/lti/assignments/{assignment_id}", _request.path.model_dump(by_alias=True)) if _request.path else "/lti/assignments/{assignment_id}"
    _http_headers = {}

    # Inject per-operation authentication
    _auth = _get_auth_for_operation("get_assignment_lti")
    _http_headers.update(_auth.get("headers", {}))

    # Execute request (returns normalized dict and status code)
    _response_data, _ = await _execute_tool_request(
        tool_name="get_assignment_lti",
        method="GET",
        path=_http_path,
        request_id=_request_id,
        headers=_http_headers,
    )

    return _response_data

