async def initiate_course_export(
    course_id: str = Field(..., description="The unique identifier of the course to export content from."),
    export_type: Literal["common_cartridge", "qti", "zip"] = Field(..., description="The format for the exported content. Common Cartridge exports course contents as .imscc, QTI exports quizzes, and zip exports files."),
    skip_notifications: bool | None = Field(None, description="Suppress notification delivery to the user upon export completion. Defaults to false, meaning notifications are sent."),
    select_folders: list[str] | None = Field(None, description="List of folder IDs to export. Supported for common_cartridge and zip export types."),
    select_files: list[str] | None = Field(None, description="List of file IDs to export. Supported for common_cartridge and zip export types."),
    select_attachments: list[str] | None = Field(None, description="List of attachment IDs to export. Supported for common_cartridge export type."),
    select_quizzes: list[str] | None = Field(None, description="List of quiz IDs to export. Supported for common_cartridge and qti export types."),
    select_assignments: list[str] | None = Field(None, description="List of assignment IDs to export. Supported for common_cartridge export type."),
    select_announcements: list[str] | None = Field(None, description="List of announcement IDs to export. Supported for common_cartridge export type."),
    select_calendar_events: list[str] | None = Field(None, description="List of calendar event IDs to export. Supported for common_cartridge export type."),
    select_discussion_topics: list[str] | None = Field(None, description="List of discussion topic IDs to export. Supported for common_cartridge export type."),
    select_modules: list[str] | None = Field(None, description="List of module IDs to export. Supported for common_cartridge export type."),
    select_module_items: list[str] | None = Field(None, description="List of module item IDs to export. Supported for common_cartridge export type."),
    select_pages: list[str] | None = Field(None, description="List of page IDs to export. Supported for common_cartridge export type."),
    select_rubrics: list[str] | None = Field(None, description="List of rubric IDs to export. Supported for common_cartridge export type.")
) -> dict[str, Any]:
    """Initiate a content export job for a course in the specified format. Track progress using the Progress API and retrieve the download URL once the export completes."""

    # Call helper functions
    select = build_select_object(select_folders, select_files, select_attachments, select_quizzes, select_assignments, select_announcements, select_calendar_events, select_discussion_topics, select_modules, select_module_items, select_pages, select_rubrics) or {}

    # Construct request model with validation
    try:
        _request = _models.ExportContentCoursesRequest(
            path=_models.ExportContentCoursesRequestPath(course_id=course_id),
            body=_models.ExportContentCoursesRequestBody(export_type=export_type, skip_notifications=skip_notifications, select=select)
        )
    except pydantic.ValidationError as _validation_err:
        logging.error(f"Parameter validation failed for initiate_course_export: {_validation_err}")
        raise ValueError(f"Invalid parameters: {_validation_err.errors()}") from _validation_err

    # Generate request ID
    _request_id = str(uuid.uuid4())

    # Log invocation
