    quiz_hide_results: Literal["always", "until_after_last_attempt"] | None = Field(None, description="Controls quiz result visibility to students. Use 'always' to permanently hide results, 'until_after_last_attempt' to show only after final attempt (requires multiple attempts), or null to show results immediately."),
